CREATE PROCEDURE [dbo].[spProductUnitConversionCheckDuplicate] @FromUnitId INT, @ToUnitId INT, @ExcludeUnitConversionId INT = NULL AS BEGIN SET NOCOUNT ON; SELECT CAST(CASE WHEN EXISTS(SELECT 1 FROM [dbo].[ProductUnitConversion] WHERE FromUnitId=@FromUnitId AND ToUnitId=@ToUnitId AND IsActive=1 AND (@ExcludeUnitConversionId IS NULL OR UnitConversionId<>@ExcludeUnitConversionId)) THEN 1 ELSE 0 END AS BIT); END;
